class Calculator:
    def __init__(self):
        self.memory = 0

    def add(self, a, b):
        result = self._calculate(a, b, '+')
        self._store(result)
        return result

    def subtract(self, a, b):
        result = self._calculate(a, b, '-')
        self._store(result)
        return result

    def _calculate(self, a, b, op):
        if op == '+':
            return a + b
        elif op == '-':
            return a - b
        return 0

    def _store(self, value):
        self.memory = value

def main():
    calc = Calculator()
    result = calc.add(5, 3)
    print(f'Result: {result}')

if __name__ == '__main__':
    main()

function formatNumber(num) {
    return num.toFixed(2);
}

function validateInput(value) {
    if (typeof value !== 'number') {
        throw new Error('Invalid input');
    }
    return true;
}

class Logger {
    constructor(name) {
        this.name = name;
    }

    log(message) {
        console.log(`[${this.name}] ${message}`);
    }

    error(message) {
        console.error(`[${this.name}] ERROR: ${message}`);
    }
}

module.exports = { formatNumber, validateInput, Logger };
